SELECT notice_id AS noticeId, member_id AS memberId, category, title, content, `count`, is_pinned AS isPinned, create_at AS createAt, update_at AS updateAt FROM notice_board
AND category = #{category}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR member_id LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY is_pinned DESC, notice_id DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(notice_id) FROM notice_board
AND category = #{category}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR member_id LIKE CONCAT('%', #{keyword}, '%'))
